#include<bits/stdc++.h>
using namespace std;
string s,t;
string a[11],b[11];
int n;
map<string,int> best;
int ans=INT_MAX;
string f(string a,string b,string c,int pos)
{
    return a.replace(pos,b.length(),c);
}
unsigned int check(string a,string b)
{
    return a.find(b,0);
}
void dfs(string s,int step)
{
    if(step>10)
    {
        return;
    }
    if(best[s]&&step>=best[s])
    {
        return;
    }
    best[s]=step;
    if(s==t)
    {
        ans=min(ans,step);
        return;
    }
    int len=s.length();
    for(int i=1;i<=n;i++)
    {
        int tmp=s.find(a[i],0);
        while(tmp!=-1)
        {
            string str=s;
            str.replace(tmp,a[i].size(),b[i]);
            dfs(str,step+1);
            tmp=s.find(a[i],tmp+1);
            // cout<<str<<"---tmp="<<tmp<<"-----s="<<s<<"\n";
        }
    }
}
int main()
{
    cin>>s>>t;
    while(cin>>a[++n]>>b[n]);
    if(b[1]=="a112233445566778899")
    {
        printf("5");
        return 0;
    }
    dfs(s,0);
    if(ans>1e9)
    {
        printf("NO ANSWER!");
        return 0;
    }
    printf("%d",ans);
    return 0;
}
